// 1. Sadə optional properties
interface User {
  name: string;
  age?: number;
}
const user1: User = { name: "Murad" };
const user2: User = { name: "Alice", age: 25 };
console.log(user1); // Çıxış: { name: "Murad" }
console.log(user2); // Çıxış: { name: "Alice", age: 25 }

// 2. Optional properties ilə funksiyalar
interface Product {
  id: string;
  name: string;
  price?: number;
}
function displayProduct(product: Product): string {
  return `${product.name} (ID: ${product.id})${product.price ? `: $${product.price}` : ""}`;
}
const book: Product = { id: "B001", name: "TypeScript Guide" };
const laptop: Product = { id: "P001", name: "Laptop", price: 1200 };
console.log(displayProduct(book)); // Çıxış: TypeScript Guide (ID: B001)
console.log(displayProduct(laptop)); // Çıxış: Laptop (ID: P001): $1200

// 3. Optional properties ilə miras alma
interface Person {
  name: string;
  age?: number;
}
interface Employee extends Person {
  role?: string;
}
const employee: Employee = { name: "Murad" };
console.log(employee); // Çıxış: { name: "Murad" }

// 4. Siniflərdə optional properties
interface Vehicle {
  brand: string;
  model?: string;
  getInfo(): string;
}
class Car implements Vehicle {
  brand: string;
  model?: string;
  constructor(brand: string, model?: string) {
    this.brand = brand;
    this.model = model;
  }
  getInfo(): string {
    return this.model ? `${this.brand} ${this.model}` : this.brand;
  }
}
const car1 = new Car("Toyota");
const car2 = new Car("Honda", "Civic");
console.log(car1.getInfo()); // Çıxış: Toyota
console.log(car2.getInfo()); // Çıxış: Honda Civic

// 5. Union tipləri ilə optional properties
interface Book {
  type: "book";
  title: string;
  pages?: number;
}
interface Movie {
  type: "movie";
  title: string;
  duration?: number;
}
type Media = Book | Movie;
function describeMedia(media: Media): string {
  if (media.type === "book") {
    return `${media.title}${media.pages ? `: ${media.pages} pages` : ""}`;
  }
  return `${media.title}${media.duration ? `: ${media.duration} minutes` : ""}`;
}
const book: Book = { type: "book", title: "TypeScript Guide" };
const movie: Movie = { type: "movie", title: "Inception", duration: 148 };
console.log(describeMedia(book)); // Çıxış: TypeScript Guide
console.log(describeMedia(movie)); // Çıxış: Inception: 148 minutes

// Sadə mağaza sistemi
interface Product {
  id: string;
  name: string;
  price?: number;
  inStock?: boolean;
}
class ProductItem implements Product {
  id: string;
  name: string;
  price?: number;
  inStock?: boolean;
  constructor(id: string, name: string, price?: number, inStock?: boolean) {
    this.id = id;
    this.name = name;
    this.price = price;
    this.inStock = inStock;
  }
  getDetails(): string {
    return `${this.name} (ID: ${this.id})${this.price ? `: $${this.price}` : ""}, ${this.inStock ? "mövcuddur" : "mövcud deyil"}`;
  }
}
const mouse = new ProductItem("P001", "Mouse", 25, true);
const keyboard = new ProductItem("P002", "Keyboard");
console.log(mouse.getDetails()); // Çıxış: Mouse (ID: P001): $25, mövcuddur
console.log(keyboard.getDetails()); // Çıxış: Keyboard (ID: P002), mövcud deyil

// Miras alma ilə
interface StockProduct extends Product {
  stockCount?: number;
}
const stockMouse: StockProduct = {
  id: "P001",
  name: "Mouse",
  stockCount: 50
};
console.log(`${stockMouse.name}: ${stockMouse.stockCount ? stockMouse.stockCount + " ədəd" : "stok məlumatı yoxdur"}`); // Çıxış: Mouse: 50 ədəd

